<template>
	<view class="container">
		<text class="welcome-text">Welcome to MT Supply Chain Management</text>
		<navigator url="/pages/login/login">
			<Mbutton content='开始旅程' class="btn">
			</Mbutton><!-- <button class="start-btn" @click="handleStart">开始体验</button> -->
		</navigator>
	</view>
</template>

<script>
	export default {
		// welcome.vue
		methods: {
			handleStart() {
				// 设置标记（添加容错处理）
				try {
					uni.setStorageSync('hasShownWelcome', true);
				} catch (e) {
					console.error('存储失败:', e);
				}

				// 直接跳转到首页（确保路径正确）
				uni.switchTab({
					url: '/pages/index/index',
					success: () => {
						// 强制关闭所有页面
						if (getCurrentPages().length > 1) {
							uni.reLaunch({
								url: '/pages/index/index'
							});
						}
					},
					fail: (err) => {
						console.error('跳转失败:', err);
						uni.navigateBack({
							delta: 999
						}); // 尝试返回首页
					}
				});
			}
		}
	}
</script>

